class CentralizedLogger:
    def __init__(self, es_host="localhost", es_port=9200):
        self.es = Elasticsearch([f"{es_host}:{es_port}"])
        self.index_name = "logs"
        self._create_index()
        
    def _create_index(self):
        if not self.es.indices.exists(index=self.index_name):
            mapping = {
                "mappings": {
                    "properties": {
                        "timestamp": {"type": "date"},
                        "level": {"type": "keyword"},
                        "message": {"type": "text"},
                        "service": {"type": "keyword"},
                        "request_id": {"type": "keyword"},
                        "tags": {"type": "keyword"}
                    }
                }
            }
            self.es.indices.create(index=self.index_name, body=mapping)
    
    def log(self, level, message, service="unknown", request_id=None, tags=None):
        log_entry = {
            "timestamp": datetime.utcnow().isoformat(),
            "level": level,
            "message": message,
            "service": service,
            "request_id": request_id or str(uuid.uuid4()),
            "tags": tags or []
        }
        
        self.es.index(index=self.index_name, body=log_entry)
    
    def search_logs(self, query, size=100, from_=0):
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "type": "best_fields",
                    "fields": ["message", "service", "tags"]
                }
            },
            "size": size,
            "from": from_,
            "sort": [{"timestamp": {"order": "desc"}}]
        }
        
        result = self.es.search(index=self.index_name, body=search_body)
        return result['hits']['hits']
    
    def search_by_level(self, level, size=100):
        search_body = {
            "query": {
                "term": {
                    "level": level
                }
            },
            "size": size,
            "sort": [{"timestamp": {"order": "desc"}}]
        }
        
        result = self.es.search(index=self.index_name, body=search_body)
        return result['hits']['hits']
    
    def search_by_service(self, service, size=100):
        search_body = {
            "query": {
                "term": {
                    "service": service
                }
            },
            "size": size,
            "sort": [{"timestamp": {"order": "desc"}}]
        }
        
        result = self.es.search(index=self.index_name, body=search_body)
        return result['hits']['hits']
    
    def get_log_statistics(self):
        agg_body = {
            "aggs": {
                "levels": {
                    "terms": {"field": "level"}
                },
                "services": {
                    "terms": {"field": "service"}
                }
            }
        }
        
        result = self.es.search(index=self.index_name, body=agg_body)
        return result['aggregations']

